INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (129, 135341, 5, 135, '不让爱在心中结冰', '又是一个人，独享着孤独，追求的是心灵的平和，但不免泛起幽幽的思愁、无名的烦躁，像杯里的咖啡，浓浓的、涩涩的，窗外歌声声声入耳，诉说的是缠绵的情意，翻翻村上的《挪威的森林》，句句扣击着我的心灵，有着强烈的共鸣。村上潇洒的把玩着孤独，而我呢，则品味着其中的枯涩，或许带着欣慰。
<br>没有情人的日子，一颗孤独的心徘徊在清秋的枫林道上，踏着沙沙的脚步，感受的是落叶的不舍与无奈，但落叶最后是幸福的，他成了树的灵魂的一部分，彻底融入大树，而心呢，何处能是他的归宿，他只能努力的朝着太阳走去，那只是他存在的希望，那阳光能使心中的冰消融――让爱不再心中结冰。', '又是一个人，独享着孤独，追求的是心灵的平和，但不免泛起幽幽的思愁、无名的烦躁，像杯里的咖啡，浓浓的、涩涩的，窗外歌声声声入耳，诉说的是缠绵的情意，翻翻村上的《挪威的森林》，句句扣击着我的心灵，有着强烈的共鸣。村上潇洒的把玩着孤独，而我呢，则品味着其中的枯涩，或许带着欣慰。

没有情人的日子，一颗孤独的心徘徊在清秋的枫林道上，踏着沙沙的脚步，感受的是落叶的不舍与无奈，但落叶最后是幸福的，他成了树的灵魂的一部分，彻底融入大树，而心呢，何处能是他的归宿，他只能努力的朝着太阳走去，那只是他存在的希望，那阳光能使心中的冰消融――让爱不再心中结冰。', NULL, '2001-12-01 15:49:00', 6, '20011225215443_bbsid_135341_board_5_749aa816a7.html', '20011225215443');
